import styled from 'styled-components';
import { Link } from 'react-router-dom';

/*
 * Nocturne palette, matched to the homepage (NewHome/GlobalStyle.js).
 * Those CSS variables only exist while NewHome is mounted, so the blog
 * pages hardcode the same values here to stay on theme on their own route.
 *
 *   wine   #150710   wine-2 #1e0a16   panel #22101d
 *   cream  #f0e6d8   cream-dim #b9a892   muted #8a7867
 *   brass  #c9a86a   brass-lo #8f7645
 *   alien  #7ff0be   alien-lo #3fae82
 *   line   rgba(201,168,106,.18)   line-2 rgba(201,168,106,.32)
 */

const DISPLAY = "'Megrim', 'Didot', 'Bodoni MT', Garamond, serif";
const SERIF = "'Didot', 'Bodoni MT', 'Hoefler Text', Garamond, 'Times New Roman', serif";
const MONO = "'SFMono-Regular', ui-monospace, Menlo, Consolas, monospace";
const UI =
  "-apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Helvetica, Arial, sans-serif";

/* ---- header ---- */

export const HeaderBar = styled.header`
  position: sticky;
  top: 0;
  z-index: 20;
  background: color-mix(in srgb, #150710 82%, transparent);
  backdrop-filter: blur(10px);
  border-bottom: 1px solid rgba(201, 168, 106, 0.18);
`;

export const HeaderInner = styled.div`
  max-width: 1060px;
  margin: 0 auto;
  padding: 0 26px;
  height: 62px;
  display: flex;
  align-items: center;
  justify-content: space-between;
`;

export const Brand = styled(Link)`
  font-family: ${DISPLAY};
  font-size: 1.6rem;
  letter-spacing: 0.04em;
  color: #f0e6d8;
  text-decoration: none;
  line-height: 1;

  span {
    color: #8f7645;
  }
  b {
    font-weight: 400;
    color: #7ff0be;
  }
  &:hover b {
    color: #f0e6d8;
  }
`;

export const NavRow = styled.nav`
  display: flex;
  align-items: center;
  gap: 24px;
  font-family: ${MONO};
  font-size: 14px;

  @media screen and (max-width: 600px) {
    gap: 16px;
    font-size: 13px;
  }
`;

export const NavA = styled.a`
  color: #b9a892;
  text-decoration: none;
  transition: color 0.18s;

  &:hover {
    color: #7ff0be;
  }

  @media screen and (max-width: 440px) {
    &.hidem {
      display: none;
    }
  }
`;

/* ---- article ---- */

export const PostContainer = styled.article`
  min-height: 100vh;
  background: #150710;
  color: #f0e6d8;
  font-family: ${UI};
  line-height: 1.6;
  padding: 70px 20px 90px;
  display: flex;
  justify-content: center;
`;

export const PostInner = styled.div`
  max-width: 760px;
  width: 100%;
`;

export const BackLink = styled.a`
  display: inline-block;
  font-family: ${MONO};
  font-size: 0.9rem;
  color: #c9a86a;
  text-decoration: none;
  margin-bottom: 34px;
  transition: color 0.18s;

  &:hover {
    color: #7ff0be;
  }
`;

export const PostCover = styled.img`
  width: 100%;
  max-height: 320px;
  object-fit: cover;
  border-radius: 12px;
  border: 1px solid rgba(201, 168, 106, 0.18);
  margin-bottom: 34px;
  box-shadow: 0 20px 44px -26px #000;
`;

export const PostTitle = styled.h1`
  font-family: ${DISPLAY};
  font-weight: 400;
  font-size: clamp(38px, 6vw, 64px);
  line-height: 1.02;
  letter-spacing: 0.005em;
  color: #f0e6d8;
  margin: 0 0 18px;
`;

export const PostSubtitle = styled.p`
  font-size: 1.2rem;
  line-height: 1.6;
  color: #b9a892;
  margin: 0 0 24px;

  @media screen and (max-width: 480px) {
    font-size: 1.08rem;
  }
`;

export const PostMeta = styled.div`
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 12px;
  font-family: ${MONO};
  font-size: 0.85rem;
  color: #8a7867;
  padding-bottom: 26px;
  margin-bottom: 42px;
  border-bottom: 1px solid rgba(201, 168, 106, 0.18);
`;

export const TagRow = styled.div`
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
`;

export const Tag = styled.span`
  font-family: ${MONO};
  font-size: 0.72rem;
  color: #b9a892;
  background: #1e0a16;
  border: 1px solid rgba(201, 168, 106, 0.32);
  border-radius: 5px;
  padding: 4px 10px;
`;

export const Paragraph = styled.p`
  font-size: 1.12rem;
  line-height: 1.78;
  color: #ddd0bd;
  margin: 0 0 24px;

  code {
    font-family: ${MONO};
    font-size: 0.9em;
    color: #7ff0be;
    background: #22101d;
    border: 1px solid rgba(201, 168, 106, 0.18);
    padding: 1px 6px;
    border-radius: 5px;
  }
`;

export const SectionHeading = styled.h2`
  font-family: ${SERIF};
  font-weight: 400;
  font-size: 1.7rem;
  letter-spacing: 0.01em;
  color: #f0e6d8;
  margin: 44px 0 16px;
`;

export const Pullquote = styled.blockquote`
  margin: 34px 0;
  padding: 6px 0 6px 24px;
  border-left: 2px solid #7ff0be;
  font-family: ${SERIF};
  font-size: 1.4rem;
  line-height: 1.5;
  font-style: italic;
  color: #f0e6d8;
`;

export const BulletList = styled.ul`
  margin: 0 0 24px;
  padding-left: 22px;
  list-style: none;

  li {
    position: relative;
    padding-left: 20px;
    font-size: 1.1rem;
    line-height: 1.7;
    color: #ddd0bd;
    margin-bottom: 12px;
  }
  li:before {
    content: '';
    position: absolute;
    left: 0;
    top: 12px;
    width: 6px;
    height: 6px;
    border-radius: 1px;
    background: #c9a86a;
    transform: rotate(45deg);
  }
`;

export const CodeBlock = styled.pre`
  background: #100610;
  border: 1px solid rgba(201, 168, 106, 0.18);
  border-radius: 10px;
  padding: 20px;
  overflow-x: auto;
  margin: 0 0 28px;

  code {
    font-family: ${MONO};
    font-size: 0.9rem;
    line-height: 1.6;
    color: #d8cbb8;
    white-space: pre;
  }
`;

/* ---- footer ---- */

export const FooterBar = styled.footer`
  border-top: 1px solid rgba(201, 168, 106, 0.18);
  background: #1e0a16;
`;

export const FooterInner = styled.div`
  max-width: 1060px;
  margin: 0 auto;
  padding: 40px 26px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 18px;
  text-align: center;
`;

export const FooterLinks = styled.div`
  display: flex;
  flex-wrap: wrap;
  gap: 24px;
  justify-content: center;
  font-family: ${MONO};
  font-size: 13px;

  a {
    color: #8a7867;
    text-decoration: none;
    transition: color 0.18s;
  }
  a:hover {
    color: #7ff0be;
  }
`;

export const FootRights = styled.span`
  font-family: ${MONO};
  font-size: 12px;
  color: #8a7867;
`;

export const NotFoundWrap = styled.div`
  min-height: 100vh;
  background: #150710;
  color: #f0e6d8;
  font-family: ${UI};
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  gap: 24px;
  text-align: center;
  padding: 20px;

  h1 {
    font-family: ${DISPLAY};
    font-weight: 400;
  }
`;
