// Console easter eggs — a small gift for anyone curious enough to open devtools.
// On-theme with the site's UFO / alien / abduction motif. Runs once on load.

/* eslint-disable no-console */

const SAUCER = `
                 _~-~-~_
             .-~\`         \`~-.
          .-'    .-~~~~~-.    '-.
         (     .'  o   o  '.     )
          \\    \\    ___    /    /
           '.   '.  '-'  .'   .'
         .---'.   '-...-'   .'---.
        /       '-._____.-'       \\
       '-.____ :: R M :: ____.-'
             \\\\     |||     //
              \\\\    |||    //
               \\\\   |||   //
                (   BEAM   )
                 '.  |||  .'
                   '.|||.'
                     \\|/
                      '`;

const mint = 'color:#7ff0be';
const mintBold = 'color:#7ff0be;font-weight:bold';
const brass = 'color:#c9a86a';
const cream = 'color:#f0e6d8';
const dim = 'color:#8a7867';

export default function consoleArt() {
  if (typeof window === 'undefined' || !window.console || !console.log) return;
  // run once even if the entry module is re-evaluated (HMR/StrictMode), so we
  // never double-print or attach the Konami listener twice
  if (window.__rmConsoleEgg) return;
  window.__rmConsoleEgg = true;

  console.log(
    `%c${SAUCER}`,
    `${mint};font-family:monospace;line-height:1.08;text-shadow:0 0 8px rgba(127,240,190,.35)`
  );
  console.log(
    '%cRyan McCauley%c — developer · tinkerer · builder',
    `${cream};font-size:15px;font-weight:bold`,
    dim
  );
  console.log('%cYou found the console. 👽  Since you are poking around under the hood:', brass);
  console.log('%c  › Everything here is hand-built. No template, no page builder.', cream);
  console.log('%c  › I am open to new developer and tech opportunities.', cream);
  console.log(
    '%c  › Say hi:  %crmccauleycode@gmail.com   %c·   %chttps://github.com/Ryan-McCauley',
    cream,
    mint,
    dim,
    mint
  );
  console.log(
    '%cpsst — try %cabduct()%c in here, or the Konami code (↑↑↓↓←→←→ B A) anywhere.',
    dim,
    mintBold,
    dim
  );

  // an interactive command: a gentle, fully reversible "beam up" wink
  window.abduct = function abduct() {
    console.log('%c🛸  tractor beam engaged…', `${mintBold};font-size:14px`);
    console.log('%c   🐄  …mooooo…', cream);
    try {
      document.body.animate(
        [
          { transform: 'translateY(0) scale(1)', filter: 'brightness(1)' },
          { transform: 'translateY(-16px) scale(1.01)', filter: 'brightness(1.25)', offset: 0.5 },
          { transform: 'translateY(0) scale(1)', filter: 'brightness(1)' },
        ],
        { duration: 1400, easing: 'ease-in-out' }
      );
    } catch {
      /* animations optional */
    }
    return '👽  take me to your recruiter';
  };

  // Konami code → same wink, plus a secret line
  const KONAMI = [
    'ArrowUp', 'ArrowUp', 'ArrowDown', 'ArrowDown',
    'ArrowLeft', 'ArrowRight', 'ArrowLeft', 'ArrowRight', 'b', 'a',
  ];
  let idx = 0;
  window.addEventListener('keydown', (e) => {
    const key = e.key.length === 1 ? e.key.toLowerCase() : e.key;
    idx = key === KONAMI[idx] ? idx + 1 : (key === KONAMI[0] ? 1 : 0);
    if (idx === KONAMI.length) {
      idx = 0;
      console.log('%c✦ CLEARANCE: PRIME ✦  the truth is out there (and so is my résumé).', mintBold);
      if (typeof window.abduct === 'function') window.abduct();
    }
  });
}
