import React from 'react';
import {
  Paragraph,
  SectionHeading,
  Pullquote,
  BulletList,
  CodeBlock,
} from './BlogPostElements';

// Render inline `code` spans written with backticks inside paragraph text.
const renderInline = (text) => {
  const parts = text.split(/(`[^`]+`)/g);
  return parts.map((part, i) => {
    if (part.startsWith('`') && part.endsWith('`')) {
      return <code key={i}>{part.slice(1, -1)}</code>;
    }
    return <React.Fragment key={i}>{part}</React.Fragment>;
  });
};

const Block = ({ block }) => {
  switch (block.type) {
    case 'h2':
      return <SectionHeading>{block.text}</SectionHeading>;
    case 'quote':
      return <Pullquote>{block.text}</Pullquote>;
    case 'ul':
      return (
        <BulletList>
          {block.items.map((item, i) => (
            <li key={i}>{renderInline(item)}</li>
          ))}
        </BulletList>
      );
    case 'code':
      return (
        <CodeBlock>
          <code>{block.code.replace(/\\n/g, '\n')}</code>
        </CodeBlock>
      );
    case 'p':
    default:
      return <Paragraph>{renderInline(block.text)}</Paragraph>;
  }
};

const BlogPostBody = ({ blocks }) => (
  <>
    {blocks.map((block, i) => (
      <Block key={i} block={block} />
    ))}
  </>
);

export default BlogPostBody;
