import { createGlobalStyle } from 'styled-components';

// Ported verbatim from the Nocturne prototype (public/nocturne.html), plus a small
// addition of .resume-menu styles for the résumé-request popover.
const NocturneGlobalStyle = createGlobalStyle`
  @font-face{font-family:"Megrim";font-style:normal;font-weight:400;font-display:swap;src:url(data:font/woff2;base64,) format("woff2")}
  :root{
    --wine:#150710; --wine-2:#1e0a16; --panel:#22101d; --panel-2:#2a1526;
    --cream:#f0e6d8; --cream-dim:#b9a892; --muted:#8a7867;
    --brass:#c9a86a; --brass-lo:#8f7645;
    --alien:#7ff0be; --alien-lo:#3fae82;
    --line:rgba(201,168,106,.18); --line-2:rgba(201,168,106,.32);
    --ui:-apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,Helvetica,Arial,sans-serif;
    --mono:"SFMono-Regular",ui-monospace,Menlo,Consolas,monospace;
    --serif:"Didot","Bodoni MT","Hoefler Text",Garamond,"Times New Roman",serif;
    --display:"Megrim","Didot","Bodoni MT",Garamond,serif;
    --maxw:1060px;
  }
  *{box-sizing:border-box}
  body{margin:0}
  .page{background:var(--wine);color:var(--cream);font-family:var(--ui);-webkit-font-smoothing:antialiased;line-height:1.6}
  .shell{max-width:var(--maxw);margin:0 auto;padding:0 26px}

  .nav{position:sticky;top:0;z-index:20;background:color-mix(in srgb,var(--wine) 82%,transparent);
    backdrop-filter:blur(10px);border-bottom:1px solid var(--line)}
  .nav .shell{display:flex;align-items:center;justify-content:space-between;height:62px}
  .brand{font-family:var(--mono);font-size:13px;letter-spacing:.04em;font-weight:600;color:var(--cream)}
  .brand b{color:var(--alien)}
  .nav ul{display:flex;gap:24px;list-style:none;margin:0;padding:0;font-size:14px}
  .nav a{color:var(--cream-dim);text-decoration:none;transition:color .18s}
  .nav a:hover{color:var(--cream)}
  .nav .resume{border:1px solid color-mix(in srgb,var(--alien) 42%,transparent);border-radius:6px;
    padding:7px 15px;color:var(--alien);font-size:12px;font-family:"Orbitron",var(--mono);
    font-weight:500;text-transform:uppercase;letter-spacing:.14em;
    background:color-mix(in srgb,var(--alien) 7%,transparent);transition:color .18s,border-color .18s,box-shadow .18s}
  .nav .resume:hover{border-color:var(--alien);color:#eafff5;
    box-shadow:0 0 16px -3px color-mix(in srgb,var(--alien) 60%,transparent)}
  @media(max-width:680px){.nav ul li.hidem{display:none}}

  .hero{position:relative;overflow:hidden;border-bottom:1px solid var(--line);cursor:none;
    background:
      radial-gradient(120% 90% at 82% 4%, rgba(127,240,190,.09), transparent 44%),
      radial-gradient(90% 90% at 6% 100%, rgba(201,168,106,.10), transparent 52%),
      linear-gradient(165deg,var(--wine-2),var(--wine) 72%)}
  .hero:before{content:"";position:absolute;inset:0;pointer-events:none;
    background-image:linear-gradient(rgba(201,168,106,.05) 1px,transparent 1px),linear-gradient(90deg,rgba(201,168,106,.05) 1px,transparent 1px);
    background-size:34px 34px}
  .hero svg.art{position:absolute;top:0;right:0;width:50%;height:100%;pointer-events:none}
  .hero svg.art path,.hero svg.art ellipse{fill:none;stroke:var(--brass-lo);stroke-width:1.1;
    stroke-dasharray:900;stroke-dashoffset:900;animation:draw 3s ease forwards}
  .hero svg.art .glow{stroke:var(--alien-lo);filter:drop-shadow(0 0 6px rgba(127,240,190,.5))}
  /* roaming UFO overlay (searchlight) - positioned & animated in JS, px-space */
  .hero .ufofield{position:absolute;inset:0;z-index:1;pointer-events:none;overflow:hidden}  /* behind the text */
  .hero .cowlayer{position:absolute;inset:0;z-index:6;pointer-events:none;overflow:hidden} /* above the text */
  .hero.beam-live{cursor:none}
  .cowlayer .cow-cursor{position:absolute;left:0;top:0;transform:translate(-50%,-50%);opacity:0;z-index:5;
    pointer-events:none;will-change:transform,left,top,opacity;filter:drop-shadow(0 2px 2px rgba(0,0,0,.55))}
  /* circular grazing meadow under the saucer (sized/placed in JS) */
  .hero .meadow{position:absolute;left:0;top:0;z-index:0;pointer-events:none;overflow:visible;
    background:linear-gradient(180deg, rgba(30,90,55,0) 0%, rgba(34,96,60,.18) 30%, rgba(22,64,36,.6) 55%, rgba(20,53,31,.96) 80%, rgba(20,53,31,.98) 100%)}
  .hero .meadow .blade{position:absolute;width:2px;border-radius:2px 2px 0 0;
    transform-origin:bottom center;transform:scaleY(1)}
  @keyframes sway{
    0%,100%{transform:scaleY(.985) rotate(calc(var(--sway,6deg) * -1))}
    25%{transform:scaleY(1.01) rotate(calc(var(--sway,6deg) * -0.3))}
    50%{transform:scaleY(.99) rotate(var(--sway,6deg))}
    75%{transform:scaleY(1.01) rotate(calc(var(--sway,6deg) * 0.3))}
  }
  /* one class flips every blade's animation off at once — used when the hero scrolls off
     screen or the tab is backgrounded, so thousands of running animations don't keep costing
     compositor/GC work while nobody can see them */
  .page.scene-paused .hero .meadow .blade{animation-play-state:paused !important}
  .page.scene-paused .foot-cow-head{animation-play-state:paused !important}
  .hero .meadow .beamlight{position:absolute;border-radius:50%;pointer-events:none;opacity:0;
    transition:opacity .25s ease;will-change:opacity,left,top,width,height;
    background:radial-gradient(ellipse at center, rgba(255,255,235,.5) 0%, rgba(190,255,215,.3) 38%, rgba(6,20,12,.3) 64%, rgba(6,20,12,0) 84%)}
  @media (prefers-reduced-motion:reduce){.hero .meadow .blade{animation:none !important}}
  .ufofield .craft{position:absolute;left:0;top:0;will-change:transform;opacity:0}
  .ufofield .craft .glow{fill:none;stroke:var(--alien-lo);stroke-width:1.4;
    filter:drop-shadow(0 0 5px rgba(127,240,190,.6))}
  .ufofield .craft .dome2{fill:none;stroke:var(--brass-lo);stroke-width:1.3}
  .ufofield .searchbeam{position:absolute;left:0;top:0;transform-origin:50% 0;will-change:transform;overflow:visible}
  .ufofield .searchbeam .cone{fill:rgba(127,240,190,.09);stroke:rgba(127,240,190,.26);stroke-width:1;opacity:0}
  .ufofield .searchbeam .core{stroke:var(--alien);stroke-width:0;opacity:0;stroke-linecap:round;
    filter:drop-shadow(0 0 6px var(--alien)) drop-shadow(0 0 14px rgba(127,240,190,.7))}
  .ufofield .captive2{position:absolute;width:16px;height:16px;transform:translate(-50%,-50%);border-radius:50%;
    background:radial-gradient(circle at 50% 34%, #eafff5, var(--alien) 58%, rgba(127,240,190,0) 74%);
    box-shadow:0 0 16px 5px rgba(127,240,190,.55);will-change:transform,opacity}
  .cowlayer .shock2{position:absolute;width:26px;height:26px;border-radius:50%;border:1.4px solid var(--alien);
    transform:translate(-50%,-50%) scale(.2)}
  .cowlayer .zap{position:absolute;width:30px;height:30px;border-radius:50%;pointer-events:none;
    transform:translate(-50%,-50%);
    background:radial-gradient(circle,#eafff8,rgba(127,240,190,.6) 40%,rgba(127,240,190,0) 70%)}
  .hero svg.art .pad{fill:var(--alien);stroke:none;opacity:0;animation:pop .4s ease 2.4s forwards}
  @keyframes draw{to{stroke-dashoffset:0}}@keyframes beam{to{opacity:.5}}@keyframes pop{to{opacity:.9}}
  .hero .shell{position:relative;z-index:2;padding:78px 26px 150px}
  .status{display:inline-flex;align-items:center;gap:9px;font-family:var(--mono);font-size:12px;letter-spacing:.06em;
    color:var(--alien);border:1px solid color-mix(in srgb,var(--alien) 34%,transparent);border-radius:999px;
    padding:6px 13px;background:color-mix(in srgb,var(--alien) 7%,transparent);text-shadow:0 0 12px rgba(127,240,190,.3)}
  .status i{width:7px;height:7px;border-radius:50%;background:var(--alien);animation:pulse 2.4s ease-out infinite}
  @keyframes pulse{0%{box-shadow:0 0 0 0 color-mix(in srgb,var(--alien) 55%,transparent)}70%{box-shadow:0 0 0 9px transparent}100%{box-shadow:0 0 0 0 transparent}}
  .hero h1{font-family:var(--display);font-weight:400;font-size:clamp(44px,7.5vw,82px);line-height:.98;margin:22px 0 0;letter-spacing:.005em;text-wrap:balance}
  .hero .role{font-family:var(--mono);font-size:clamp(13px,1.9vw,15.5px);color:var(--brass);margin:18px 0 0;letter-spacing:.03em;line-height:1.5}
  .hero .role b{color:var(--cream);font-weight:400}
  .hero .pitch{font-size:16.5px;color:var(--cream-dim);margin:24px 0 0;max-width:64ch;line-height:1.75}
  .hero .pitch b{color:var(--cream);font-weight:500}
  .hero .cta{display:flex;flex-wrap:wrap;gap:12px;margin-top:30px}
  .btn{font-size:13px;font-family:var(--mono);letter-spacing:.06em;font-weight:600;text-decoration:none;padding:13px 22px;
    border-radius:4px;transition:transform .18s,box-shadow .18s,background .18s,color .18s;cursor:pointer;display:inline-flex;gap:8px;align-items:center;text-transform:uppercase}
  .btn.primary{background:var(--alien);color:var(--wine)}
  .btn.primary:hover{transform:translateY(-2px);box-shadow:0 12px 30px -12px var(--alien)}
  .btn.ghost{background:transparent;color:var(--brass);border:1px solid var(--line-2)}
  .btn.ghost:hover{border-color:var(--alien);color:var(--alien)}

  /* metric band */
  .metrics{border-bottom:1px solid var(--line);background:var(--wine-2)}
  .metrics .shell{display:grid;grid-template-columns:repeat(4,1fr);gap:1px;padding:0}
  .metric{padding:26px 20px;text-align:center;border-right:1px solid var(--line)}
  .metric:last-child{border-right:0}
  .metric .n{font-family:var(--serif);font-size:clamp(28px,4vw,42px);color:var(--alien);line-height:1}
  .metrics.identity .metric .n{font-size:clamp(20px,2.4vw,28px)}
  .metric .l{font-family:var(--mono);font-size:11px;letter-spacing:.08em;color:var(--cream-dim);margin-top:10px;text-transform:uppercase}
  @media(max-width:680px){.metrics .shell{grid-template-columns:1fr 1fr}.metric:nth-child(2){border-right:0}.metric:nth-child(1),.metric:nth-child(2){border-bottom:1px solid var(--line)}}

  section{padding:64px 0}
  .sec-head{display:flex;align-items:baseline;gap:16px;margin-bottom:32px}
  .sec-head .idx{font-family:var(--mono);font-size:12px;color:var(--alien)}
  .sec-head h2{font-family:var(--display);font-weight:400;font-size:clamp(24px,3.4vw,36px);margin:0;letter-spacing:.01em}
  .sec-head .rule{flex:1;height:1px;background:var(--line)}
  .sec-head .campfire{width:26px;height:26px;align-self:center;overflow:visible}
  .sec-head .campfire .flame{fill:var(--alien);transform-box:fill-box;transform-origin:50% 100%}
  .sec-head .campfire .flame-back{opacity:.55}
  .sec-head .campfire .flame-front{fill:#f0c26a}
  .sec-head .campfire .flame-back{animation:flameFlickerBack 1.7s ease-in-out infinite}
  .sec-head .campfire .flame-front{animation:flameFlickerFront 1.3s ease-in-out infinite}
  .sec-head .campfire .puff{fill:rgba(240,230,216,.4)}
  .sec-head .campfire .puff-1{animation:smokePuff 2.6s ease-out infinite}
  .sec-head .campfire .puff-2{animation:smokePuff 2.6s ease-out infinite .8s}
  .sec-head .campfire .puff-3{animation:smokePuff 2.6s ease-out infinite 1.6s}
  @keyframes flameFlickerBack{
    0%,100%{transform:scaleY(1) scaleX(1) rotate(0deg)}
    30%{transform:scaleY(1.08) scaleX(.95) rotate(-2deg)}
    60%{transform:scaleY(.94) scaleX(1.04) rotate(1deg)}
  }
  @keyframes flameFlickerFront{
    0%,100%{transform:scaleY(1) scaleX(1) rotate(0deg)}
    40%{transform:scaleY(.9) scaleX(1.06) rotate(2deg)}
    70%{transform:scaleY(1.1) scaleX(.92) rotate(-1deg)}
  }
  @keyframes smokePuff{
    0%{transform:translate(0,0) scale(.7);opacity:0}
    15%{opacity:.5}
    100%{transform:translate(4px,-22px) scale(1.8);opacity:0}
  }
  @media (prefers-reduced-motion: reduce){
    .sec-head .campfire .flame,.sec-head .campfire .puff{animation:none}
  }

  .sec-head .radar{width:26px;height:26px;align-self:center;overflow:visible;color:var(--alien)}
  .sec-head .radar .ring{fill:none;stroke:currentColor;stroke-width:1}
  .sec-head .radar .ring-1{opacity:.5}
  .sec-head .radar .ring-2{opacity:.32}
  .sec-head .radar .ring-3{opacity:.18}
  .sec-head .radar .sweep-group{transform-box:view-box;transform-origin:30px 30px;animation:radarSpin 2.4s linear infinite}
  .sec-head .radar .sweep{fill:currentColor;opacity:.28}
  .sec-head .radar .dot{fill:currentColor}
  .sec-head .radar .blip{fill:currentColor}
  .sec-head .radar .blip-1{animation:radarBlip 2.4s ease-in-out infinite}
  .sec-head .radar .blip-2{animation:radarBlip 2.4s ease-in-out infinite 1.2s}
  @keyframes radarSpin{from{transform:rotate(0deg)}to{transform:rotate(360deg)}}
  @keyframes radarBlip{
    0%,20%{opacity:0;transform:scale(.4)}
    30%{opacity:1;transform:scale(1.2)}
    45%,100%{opacity:0;transform:scale(.4)}
  }
  @media (prefers-reduced-motion: reduce){
    .sec-head .radar .sweep-group,.sec-head .radar .blip{animation:none}
  }

  .sec-head .catapult{width:30px;height:30px;align-self:center;overflow:visible;color:var(--alien)}
  .sec-head .catapult .cat-base{opacity:.85}
  .sec-head .catapult .cat-arm{transform-box:view-box;transform-origin:30px 31px;animation:catThrow 7s ease-in-out infinite}
  .sec-head .catapult .cat-ball{animation:catBallHide 7s ease-in-out infinite}
  /* overhand throw. arm rests at ~7 o'clock (0deg), holds, then whips up to
     ~1 o'clock (165deg) where it launches the rock (rock timer fires at 40% of
     the 7s loop), then returns slowly back to 7 o'clock over the rest of the
     cycle. a positive rotation sweeps up-and-over toward where the rock flies;
     a negative one scooped sideways along the bottom, reading as underhand. */
  @keyframes catThrow{
    0%{transform:rotate(0deg)}
    34%{transform:rotate(0deg);animation-timing-function:cubic-bezier(.4,0,.7,1)}
    40%{transform:rotate(165deg);animation-timing-function:ease-in-out}
    100%{transform:rotate(0deg)}
  }
  /* ball is loaded through the wind-up and up-swing, vanishes the instant it is
     launched, and reappears (reloaded) once the arm has returned to rest */
  @keyframes catBallHide{
    0%,40%{opacity:1}
    42%,96%{opacity:0}
    100%{opacity:1}
  }
  @media (prefers-reduced-motion: reduce){
    .sec-head .catapult .cat-arm,.sec-head .catapult .cat-ball{animation:none}
  }

  /* absolute + page-coordinate rocks so landed ones scroll with the page and
     stay on the ground line (fixed would leave them floating on scroll) */
  .rock-stage{position:absolute;top:0;left:0;width:100%;height:0;z-index:40;pointer-events:none;overflow:visible}
  .flying-rock{position:absolute;width:9px;height:9px;margin:-4.5px 0 0 -4.5px;border-radius:50%;
    background:var(--alien);box-shadow:0 0 6px rgba(163,235,197,.6);will-change:transform}

  /* experience timeline */
  .xp{display:flex;flex-direction:column;gap:0}
  .job{display:grid;grid-template-columns:180px 1fr;gap:24px;padding:26px 0;border-top:1px solid var(--line)}
  .job:last-child{border-bottom:1px solid var(--line)}
  .job .when{font-family:var(--mono);font-size:12.5px;color:var(--brass)}
  .job .when .loc{display:block;color:var(--muted);margin-top:6px;font-size:11.5px}
  .job h3{font-family:var(--serif);font-size:21px;font-weight:400;margin:0 0 4px;letter-spacing:.01em}
  .job .co{font-family:var(--mono);font-size:12.5px;color:var(--cream-dim);margin:0 0 14px}
  .job ul{margin:0;padding:0;list-style:none;display:flex;flex-direction:column;gap:9px}
  .job li{position:relative;padding-left:18px;font-size:14.5px;color:var(--cream-dim);line-height:1.6}
  .job li:before{content:"";position:absolute;left:0;top:9px;width:5px;height:5px;border-radius:1px;background:var(--brass);transform:rotate(45deg)}
  .job li b{color:var(--cream);font-weight:600}
  @media(max-width:680px){.job{grid-template-columns:1fr;gap:12px}}

  /* projects */
  .work{display:grid;grid-template-columns:1fr 1fr;gap:16px}
  @media(max-width:680px){.work{grid-template-columns:1fr}}
  .card{background:var(--panel);border:1px solid var(--line);border-radius:12px;padding:24px;display:flex;flex-direction:column;
    text-decoration:none;color:inherit;transition:transform .2s,border-color .2s,box-shadow .2s;position:relative;overflow:hidden}
  .card:before{content:"";position:absolute;left:0;top:0;bottom:0;width:2px;background:var(--alien);transform:scaleY(0);transform-origin:top;transition:transform .24s ease}
  .card:hover{transform:translateY(-3px);border-color:var(--line-2);box-shadow:0 20px 44px -26px #000}
  .card:hover:before{transform:scaleY(1)}
  .card .top{display:flex;justify-content:space-between;align-items:center;margin-bottom:14px}
  .card .no{font-family:var(--mono);font-size:12px;color:var(--muted)}
  .card .gh{font-family:var(--mono);font-size:12px;color:var(--brass)}
  .card:hover .gh{color:var(--alien)}
  .card h3{font-family:var(--serif);font-size:22px;margin:0 0 4px;font-weight:400;letter-spacing:.01em}
  .card .yr{font-family:var(--mono);font-size:11px;color:var(--muted);margin-bottom:10px}
  .card p{font-size:14px;color:var(--cream-dim);margin:0 0 16px;line-height:1.62;flex:1}
  .tags{display:flex;flex-wrap:wrap;gap:7px}
  .tag{font-family:var(--mono);font-size:11px;color:var(--cream-dim);background:var(--wine);border:1px solid var(--line-2);border-radius:5px;padding:4px 9px}

  /* skills */
  .stack{display:grid;grid-template-columns:repeat(auto-fit,minmax(160px,1fr));gap:1px;background:var(--line);
    border:1px solid var(--line);border-radius:12px;overflow:hidden}
  /* below ~820px only 3 of 4 categories fit per row, orphaning the 4th with two
     empty cells — force a clean 2x2 grid instead */
  @media(max-width:820px){.stack{grid-template-columns:repeat(2,minmax(0,1fr))}}
  .stack .cat{background:var(--panel);padding:20px}
  .stack .cat h3{font-family:var(--mono);font-size:11px;letter-spacing:.16em;text-transform:uppercase;color:var(--brass);margin:0 0 12px}
  .stack .cat ul{list-style:none;margin:0;padding:0;display:flex;flex-wrap:wrap;gap:7px;font-size:13px}
  .stack .cat li{color:var(--cream);background:var(--wine);border:1px solid var(--line);border-radius:5px;padding:4px 9px;font-family:var(--mono);font-size:11.5px}

  /* writing */
  .writing{display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:16px}
  @media(max-width:680px){.writing{grid-template-columns:1fr}}
  /* "coming soon" as a strip of caution/crime-scene tape: brass label, stenciled
     dark mono text, hazard-striped top & bottom edges, taped on slightly askew */
  .card .soon{position:relative;display:inline-block;margin:-2px 0 14px;
    font-family:var(--mono);font-size:10px;font-weight:700;letter-spacing:.2em;
    text-transform:uppercase;color:#1a0c04;background:var(--brass);
    padding:9px 14px 8px;transform:rotate(-1.6deg);transform-origin:left center;
    box-shadow:0 3px 12px -4px rgba(0,0,0,.6)}
  .card .soon::before,.card .soon::after{content:"";position:absolute;left:0;right:0;height:5px;
    background:repeating-linear-gradient(-45deg,#1a0c04 0 5px,transparent 5px 10px)}
  .card .soon::before{top:0}
  .card .soon::after{bottom:0}

  .foot{position:relative;overflow:hidden;min-height:520px;border-top:1px solid var(--line);
    background:linear-gradient(180deg,#0c0710 0%,#180a16 42%,#0c1810 100%)}
  .foot .foot-scene{position:absolute;inset:0;z-index:0;pointer-events:none}
  /* fixed independently of the scene SVG's own viewBox/slice scaling, so it never drifts
     when the footer's height changes (e.g. from the typewriter text) */
  .foot .moon-fixed{position:absolute;top:6%;right:6%;width:min(140px,16vw);height:min(140px,16vw);
    z-index:0;pointer-events:none}
  .foot .foot-scene svg{position:absolute;bottom:0;left:0;width:100%;height:100%;display:block}
  .foot .shell{position:relative;z-index:2;padding:74px 26px 230px;text-align:center}
  @keyframes tw{0%,100%{opacity:.25}50%{opacity:1}}
  @keyframes ufobob{0%,100%{transform:translateY(0)}50%{transform:translateY(-6px)}}
  .foot-scene .tw{animation:tw 3s ease-in-out infinite}
  .foot-scene .ufo2{animation:ufobob 4.5s ease-in-out infinite;transform-box:view-box;transform-origin:center}
  @keyframes cowChew{0%,100%{transform:rotate(0deg) translateY(0)}50%{transform:rotate(-2deg) translateY(1px)}}
  .foot-cow-head{transform-box:fill-box;transform-origin:100% 55%;animation:cowChew 2.6s ease-in-out infinite}
  .foot-cow{will-change:transform}
  @media(prefers-reduced-motion:reduce){.foot-scene .tw,.foot-scene .ufo2,.foot-cow-head{animation:none}}
  /* a tiny UFO in place of the pointer over the footer — matches the "avoid the mouse" bit */
  .foot .links a{cursor:url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' width='34' height='22' viewBox='0 0 34 22'><ellipse cx='17' cy='15' rx='15' ry='5' fill='rgb(244,236,224)' stroke='rgb(127,240,190)' stroke-width='1.4'/><ellipse cx='17' cy='8' rx='8' ry='6.5' fill='rgba(127,240,190,0.35)' stroke='rgb(127,240,190)' stroke-width='1.2'/><circle cx='17' cy='15' r='2' fill='rgb(43,21,38)'/></svg>") 17 15, auto}
  .foot h2{font-family:var(--display);font-weight:400;font-size:clamp(28px,5vw,48px);margin:0 0 14px;letter-spacing:.01em}
  .foot h2 em{font-style:italic;color:var(--alien)}
  .foot h2 em .caret{display:inline-block;width:2px;height:.85em;margin-left:2px;margin-bottom:-.08em;
    background:currentColor;animation:caretBlink 1s step-end infinite}
  @keyframes caretBlink{0%,49%{opacity:1}50%,100%{opacity:0}}
  @media(prefers-reduced-motion:reduce){.foot h2 em .caret{animation:none}}
  .foot p{color:var(--cream-dim);margin:0 auto 28px;max-width:48ch}
  .foot .links{display:flex;gap:24px;justify-content:center;flex-wrap:wrap;font-family:var(--mono);font-size:13px;margin-top:32px}
  .foot .links a{color:var(--muted);text-decoration:none}
  .foot .links a:hover{color:var(--alien)}
  /* sits below the whole footer scene (cow/UFO artwork), not inside it */
  .rights{margin:0;padding:18px 26px;text-align:center;background:var(--wine);
    border-top:1px solid var(--line);font-family:var(--mono);font-size:11px;
    letter-spacing:.02em;color:var(--muted)}

  .note{max-width:var(--maxw);margin:22px auto 60px;padding:14px 18px;border:1px dashed var(--line-2);border-radius:10px;
    font-size:13px;color:var(--cream-dim);background:var(--panel);font-family:var(--mono)}
  .note b{color:var(--brass)}
  @media (prefers-reduced-motion:reduce){.hero svg.art *{animation:none!important;stroke-dashoffset:0!important;opacity:.5!important}.status i{animation:none!important}}

  /* resume/contact trigger buttons (résumé isn't published — these open the modal below) */
  button.resume{background:none;font-family:inherit;cursor:pointer}
  .foot-trigger{background:none;border:none;padding:0;color:var(--muted);font-family:var(--mono);
    font-size:13px;text-decoration:none;cursor:pointer;transition:color .18s}
  .foot-trigger:hover{color:var(--alien)}

  /* centered contact modal — shared by "Request Résumé" and "Get in touch" */
  .modal-backdrop{position:fixed;inset:0;z-index:300;display:flex;align-items:center;justify-content:center;
    background:rgba(8,3,7,.74);backdrop-filter:blur(4px);-webkit-backdrop-filter:blur(4px);
    padding:24px;animation:modalFade .22s ease}
  .modal-panel{position:relative;width:100%;max-width:480px;max-height:calc(100vh - 48px);overflow:auto;
    background:var(--panel);border:1px solid var(--line-2);border-radius:18px;padding:40px 38px;
    box-shadow:0 50px 110px -30px rgba(0,0,0,.85);text-align:left;animation:modalPop .3s cubic-bezier(.2,.9,.3,1)}
  .modal-panel:focus{outline:none}
  .modal-close{position:absolute;top:18px;right:18px;width:34px;height:34px;border-radius:9px;
    border:1px solid var(--line);background:transparent;color:var(--muted);font-size:22px;line-height:1;
    cursor:pointer;transition:color .18s,border-color .18s}
  .modal-close:hover{color:var(--alien);border-color:var(--alien)}
  .modal-eyebrow{margin:0 0 8px;font-family:var(--mono);font-size:12px;letter-spacing:.1em;
    text-transform:uppercase;color:var(--brass)}
  .modal-panel h3{margin:0 auto 16px;font-family:var(--display);font-weight:400;color:var(--cream);
    font-size:clamp(24px,3.4vw,32px);line-height:1.2;letter-spacing:.005em;max-width:88%;text-align:center}
  .modal-note{margin:0 0 28px;font-size:15px;line-height:1.65;color:var(--cream-dim)}
  .modal-actions{display:flex;flex-direction:column;gap:12px}
  .modal-action{display:flex;align-items:center;gap:16px;padding:16px 18px;border-radius:12px;
    background:var(--wine);border:1px solid var(--line);color:var(--cream);text-decoration:none;
    transition:border-color .18s,transform .18s,background .18s}
  .modal-action:hover{border-color:var(--alien);transform:translateY(-2px);background:var(--wine-2)}
  .modal-action-icon{flex:none;display:flex;align-items:center;justify-content:center;width:38px;height:38px;
    border-radius:9px;background:rgba(127,240,190,.1);color:var(--alien);font-size:18px}
  .modal-action-copy{display:flex;flex-direction:column;gap:2px;font-size:14.5px;color:var(--cream)}
  .modal-action-copy b{font-family:var(--mono);font-size:11px;letter-spacing:.07em;
    text-transform:uppercase;color:var(--alien);font-weight:600}
  @keyframes modalFade{from{opacity:0}to{opacity:1}}
  @keyframes modalPop{from{opacity:0;transform:scale(.94) translateY(10px)}to{opacity:1;transform:scale(1) translateY(0)}}
  @media(prefers-reduced-motion:reduce){.modal-backdrop,.modal-panel{animation:none}}
  @media(max-width:480px){.modal-panel{padding:32px 24px}}

`;

export default NocturneGlobalStyle;
