import React, { useEffect } from 'react';
import { useParams } from 'react-router-dom';
import BlogPostBody from '../components/BlogPost';
import {
  HeaderBar,
  HeaderInner,
  Brand,
  NavRow,
  NavA,
  PostContainer,
  PostInner,
  BackLink,
  PostCover,
  PostTitle,
  PostSubtitle,
  PostMeta,
  TagRow,
  Tag,
  FooterBar,
  FooterInner,
  FooterLinks,
  FootRights,
  NotFoundWrap,
} from '../components/BlogPost/BlogPostElements';
import { getPostBySlug } from '../data/blogPosts';

const formatDate = (iso) =>
  new Date(`${iso}T00:00:00`).toLocaleDateString('en-US', {
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  });

const BlogHeader = () => (
  <HeaderBar>
    <HeaderInner>
      <Brand to="/">
        <span>::</span>
        <b>RM</b>
        <span>::</span>
      </Brand>
      <NavRow>
        <NavA href="/#work">Projects</NavA>
        <NavA className="hidem" href="/#writing">
          Writing
        </NavA>
        <NavA href="/#contact">Contact</NavA>
      </NavRow>
    </HeaderInner>
  </HeaderBar>
);

const BlogFooter = () => (
  <FooterBar>
    <FooterInner>
      <FooterLinks>
        <a href="/">Home</a>
        <a href="/#work">Projects</a>
        <a href="/#writing">Writing</a>
        <a href="/#contact">Contact</a>
        <a
          href="https://github.com/Ryan-McCauley"
          target="_blank"
          rel="noreferrer"
        >
          GitHub
        </a>
      </FooterLinks>
      <FootRights>© Ryan McCauley {new Date().getFullYear()}</FootRights>
    </FooterInner>
  </FooterBar>
);

const BlogPostPage = () => {
  const { slug } = useParams();
  const post = getPostBySlug(slug);

  useEffect(() => {
    window.scrollTo(0, 0);
  }, [slug]);

  // Per-post SEO. This is a client-rendered SPA, so instead of adding a head
  // manager we mutate the static tags from index.html in place (no duplicates)
  // and restore them on navigate-away. Googlebot renders JS, so it picks these
  // up; the static homepage tags remain the default for everything else.
  useEffect(() => {
    if (!post) return undefined;
    const url = `https://www.ryanmccauley.com/blog/${post.slug}`;
    const prevTitle = document.title;
    document.title = `${post.title} — Ryan McCauley`;

    const setAttr = (selector, attr, value) => {
      const el = document.head.querySelector(selector);
      if (!el) return () => {};
      const prev = el.getAttribute(attr);
      el.setAttribute(attr, value);
      return () => el.setAttribute(attr, prev);
    };

    const restorers = [
      setAttr('meta[name="description"]', 'content', post.subtitle),
      setAttr('link[rel="canonical"]', 'href', url),
      setAttr('meta[property="og:type"]', 'content', 'article'),
      setAttr('meta[property="og:title"]', 'content', post.title),
      setAttr('meta[property="og:description"]', 'content', post.subtitle),
      setAttr('meta[property="og:url"]', 'content', url),
      setAttr('meta[name="twitter:title"]', 'content', post.title),
      setAttr('meta[name="twitter:description"]', 'content', post.subtitle),
    ];

    return () => {
      document.title = prevTitle;
      restorers.forEach((restore) => restore());
    };
  }, [post]);

  if (!post) {
    return (
      <>
        <BlogHeader />
        <NotFoundWrap>
          <h1>Post not found</h1>
          <BackLink href="/#writing">&larr; Back to all posts</BackLink>
        </NotFoundWrap>
        <BlogFooter />
      </>
    );
  }

  return (
    <>
      <BlogHeader />
      <PostContainer>
        <PostInner>
          <BackLink href="/#writing">&larr; Back to all posts</BackLink>
          <PostCover src={post.cover} alt={post.title} />
          <PostTitle>{post.title}</PostTitle>
          <PostSubtitle>{post.subtitle}</PostSubtitle>
          <PostMeta>
            <span>{formatDate(post.date)}</span>
            <span>·</span>
            <span>{post.readingTime}</span>
            <TagRow>
              {post.tags.map((tag) => (
                <Tag key={tag}>{tag}</Tag>
              ))}
            </TagRow>
          </PostMeta>
          <BlogPostBody blocks={post.blocks} />
          <BackLink href="/#writing" style={{ marginTop: '48px' }}>
            &larr; Back to all posts
          </BackLink>
        </PostInner>
      </PostContainer>
      <BlogFooter />
    </>
  );
};

export default BlogPostPage;
