import React, { useEffect, useRef, useState } from 'react';
import ReactDOM from 'react-dom';

const EMAIL = 'rmccauleycode@gmail.com';
const LINKEDIN = 'https://www.linkedin.com/in/ryan-mccauley-30a11b216/';

// Résumé isn't published publicly — this opens a centered modal pointing interested
// people at email / LinkedIn instead of a downloadable PDF. Also doubles as the
// "Get in touch" contact dialog so there's one consistent, polished entry point.
const ResumeMenu = ({ variant = 'nav', className = '', label: labelProp }) => {
  const [open, setOpen] = useState(false);
  const [copied, setCopied] = useState(false);
  const panelRef = useRef(null);
  const triggerRef = useRef(null);
  const copyResetRef = useRef(null);

  const copyEmail = async () => {
    try {
      if (navigator.clipboard && navigator.clipboard.writeText) {
        await navigator.clipboard.writeText(EMAIL);
      } else {
        // fallback for browsers without the async clipboard API
        const ta = document.createElement('textarea');
        ta.value = EMAIL;
        ta.style.position = 'fixed';
        ta.style.opacity = '0';
        document.body.appendChild(ta);
        ta.select();
        document.execCommand('copy');
        document.body.removeChild(ta);
      }
      setCopied(true);
      clearTimeout(copyResetRef.current);
      copyResetRef.current = setTimeout(() => setCopied(false), 1800);
    } catch (err) {
      // if copying fails, fall back to opening the mail client
      window.location.href = `mailto:${EMAIL}`;
    }
  };

  useEffect(() => () => clearTimeout(copyResetRef.current), []);

  useEffect(() => {
    if (!open) return undefined;
    const onKey = (e) => { if (e.key === 'Escape') setOpen(false); };
    document.addEventListener('keydown', onKey);
    const prevOverflow = document.body.style.overflow;
    document.body.style.overflow = 'hidden';
    // tells the hero/footer scene to pause and stay paused while this is open, so nothing
    // keeps animating behind the dimmed backdrop
    window.dispatchEvent(new CustomEvent('app:modal', { detail: true }));
    const focusT = setTimeout(() => { if (panelRef.current) panelRef.current.focus(); }, 10);
    return () => {
      document.removeEventListener('keydown', onKey);
      document.body.style.overflow = prevOverflow;
      window.dispatchEvent(new CustomEvent('app:modal', { detail: false }));
      clearTimeout(focusT);
      if (triggerRef.current) triggerRef.current.focus();
    };
  }, [open]);

  let triggerClass = 'resume';
  let label = <>résumé <span aria-hidden="true">&#8599;</span></>;
  if (variant === 'button') { triggerClass = 'btn primary'; label = 'Request Résumé'; }
  else if (variant === 'footer') { triggerClass = 'foot-trigger'; label = 'Résumé'; }
  if (labelProp) label = labelProp;

  return (
    <>
      <button
        ref={triggerRef}
        type="button"
        className={className ? `${triggerClass} ${className}` : triggerClass}
        onClick={() => setOpen(true)}
        aria-haspopup="dialog"
        aria-expanded={open}
      >
        {label}
      </button>
      {open && ReactDOM.createPortal(
        <div className="modal-backdrop" onMouseDown={(e) => { if (e.target === e.currentTarget) setOpen(false); }}>
          <div className="modal-panel" role="dialog" aria-modal="true" aria-label="Get in touch" ref={panelRef} tabIndex={-1}>
            <button type="button" className="modal-close" onClick={() => setOpen(false)} aria-label="Close">
              &times;
            </button>
            <p className="modal-eyebrow">Let&rsquo;s talk</p>
            <h3>My résumé isn&rsquo;t public &mdash; but I am.</h3>
            <p className="modal-note">
              Reach out directly below and I&rsquo;ll ship it your way.
            </p>
            <div className="modal-actions">
              <button
                type="button"
                className="modal-action"
                onClick={copyEmail}
                aria-label={copied ? 'Email address copied' : `Copy email address ${EMAIL}`}
                style={{ width: '100%', textAlign: 'left', font: 'inherit', cursor: 'pointer' }}
              >
                <span className="modal-action-icon" aria-hidden="true">{copied ? '✓' : '✉'}</span>
                <span className="modal-action-copy">
                  <b>{copied ? 'Copied' : 'Email'}</b>
                  {copied ? 'Copied to clipboard' : EMAIL}
                </span>
              </button>
              <a href={LINKEDIN} target="_blank" rel="noopener noreferrer" className="modal-action">
                <span className="modal-action-icon" aria-hidden="true">&#8599;</span>
                <span className="modal-action-copy"><b>LinkedIn</b>Connect with me</span>
              </a>
            </div>
          </div>
        </div>,
        document.body
      )}
    </>
  );
};

export default ResumeMenu;
