import React from 'react';
import './App.css';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';

import Home from './pages';
import BlogPostPage from './pages/blogPost';
import HomunculusPage from './pages/homunculus';

function App() {
  return (
    <Router>
      <Routes>
        <Route path='/' element={<Home />} />
        <Route path='/blog/:slug' element={<BlogPostPage />} />
        <Route path='/homunculus' element={<HomunculusPage />} />
        {/* legacy off-theme demo/admin routes were retired; send any old or
            unknown URL back to the homepage instead of a blank/404 page */}
        <Route path='*' element={<Navigate to='/' replace />} />
      </Routes>
    </Router>
  );
}

export default App;
